settings.custom_css:
 .btn{
  --btn-bg-1: #e270ae;
  --btn-bg-2: #D52F89;
  --btn-bg-color: #e270ae;
  --radii: 0.5em;
  cursor: pointer;
  transition: 1.8s;
  background-size: 280% auto;
  background-image: linear-gradient(
    325deg,
    var(--btn-bg-2) 0%,
    var(--btn-bg-1) 55%,
    var(--btn-bg-2) 90%
  );
  border: none;
  border-radius: var(--radii);
  color: var(--btn-bg-color);
}

.btn:hover {
  background-position: right top;
}

.btn:is(:focus, :focus-visible, :active) {
  outline: none;
}

@media (prefers-reduced-motion: reduce) {
  .btn {
    transition: linear;
  }
}

