page_settings.custom_css:
html, body{
overflow-x: hidden !important;
}

/* AJUSTE DO SCROLL LATERAL */
html, body{
overflow-x: hidden !important;
}

/* CONTEINER PAI */
.text-wrapper {
    display: flex;
    padding-top: 10px;
    padding-bottom: 5px;
}

/* FAIXA NUMERO 1 */
#text-wrapper1 {
    background: #450E2C;
}

/* TEXTO INTEIRO DA FAIXA */
.text-wrapper h1 {
    white-space: nowrap;
    font-family: "Helvetica";
    font-size: 15px;
    text-transform: uppercase;
    display: inline;
}

/* TEXTO DA FAIXA NUMERO 1 */
#text-wrapper1 h1 {
    color: white;
    animation: animafaixa 5s linear infinite;
}

/* ANIMAÇÃO DA FAIXA */
@keyframes animafaixa {
    0% {
        transform: translateX(0%);
    } 100% {
        transform:translate(-100%);
    }
}
